mapper.select:
SELECT c.id AS course_id, c.name AS course_name, c.code AS course_code, u.real_name AS teacher_name, c.semester, (SELECT COUNT(*) FROM course_student cs WHERE cs.course_id = c.id) AS enrolled_count, (SELECT COUNT(*) FROM assignment a WHERE a.course_id = c.id) AS assignment_count, (SELECT COUNT(DISTINCT sub.id) FROM assignment a2 INNER JOIN submission sub ON sub.assignment_id = a2.id WHERE a2.course_id = c.id) AS submitted_count, (SELECT (SELECT COUNT(*) FROM course_student cs WHERE cs.course_id = c.id) * (SELECT COUNT(*) FROM assignment a WHERE a.course_id = c.id) - (SELECT COUNT(DISTINCT sub.id) FROM assignment a2 INNER JOIN submission sub ON sub.assignment_id = a2.id WHERE a2.course_id = c.id)) AS unsubmitted_count, ROUND((SELECT COUNT(DISTINCT sub.id) FROM assignment a2 INNER JOIN submission sub ON sub.assignment_id = a2.id WHERE a2.course_id = c.id) * 100.0 / NULLIF((SELECT COUNT(*) FROM course_student cs WHERE cs.course_id = c.id) * (SELECT COUNT(*) FROM assignment a WHERE a.course_id = c.id), 0), 1) AS submission_rate, (SELECT COUNT(*) FROM assignment a2 INNER JOIN submission sub ON sub.assignment_id = a2.id WHERE a2.course_id = c.id AND sub.is_late = 1) AS late_count, ROUND((SELECT COUNT(*) FROM assignment a2 INNER JOIN submission sub ON sub.assignment_id = a2.id WHERE a2.course_id = c.id AND sub.is_late = 1) * 100.0 / NULLIF((SELECT COUNT(*) FROM assignment a2 INNER JOIN submission sub ON sub.assignment_id = a2.id WHERE a2.course_id = c.id), 0), 1) AS late_rate, ROUND((SELECT AVG(g.score) FROM grade g INNER JOIN submission s ON g.submission_id = s.id INNER JOIN assignment a3 ON s.assignment_id = a3.id WHERE a3.course_id = c.id), 1) AS average_score, (SELECT MAX(g.score) FROM grade g INNER JOIN submission s ON g.submission_id = s.id INNER JOIN assignment a3 ON s.assignment_id = a3.id WHERE a3.course_id = c.id) AS highest_score, (SELECT MIN(g.score) FROM grade g INNER JOIN submission s ON g.submission_id = s.id INNER JOIN assignment a3 ON s.assignment_id = a3.id WHERE a3.course_id = c.id) AS lowest_score, ROUND((SELECT COUNT(*) FROM grade g INNER JOIN submission s ON g.submission_id = s.id INNER JOIN assignment a3 ON s.assignment_id = a3.id WHERE a3.course_id = c.id AND g.score >= 60) * 100.0 / NULLIF((SELECT COUNT(*) FROM grade g INNER JOIN submission s ON g.submission_id = s.id INNER JOIN assignment a3 ON s.assignment_id = a3.id WHERE a3.course_id = c.id), 0), 1) AS pass_rate, (SELECT COUNT(*) FROM grade g INNER JOIN submission s ON g.submission_id = s.id INNER JOIN assignment a3 ON s.assignment_id = a3.id WHERE a3.course_id = c.id) AS graded_count FROM course c LEFT JOIN user u ON c.teacher_id = u.id WHERE 1=1 AND c.teacher_id = #{teacherId}
AND (c.name LIKE CONCAT('%', #{keyword}, '%') OR c.code LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY c.created_at DESC
